                &lt;div style="margin-bottom: 3px;"&gt;3. &lt;strong&gt;[Measurable outcome using an action verb]&lt;/strong&gt;&lt;/div&gt;
            &lt;/div&gt;
        &lt;/div&gt;

        &lt;div style="border-top: 1px solid {COLORS['Border']}; margin: 0 -28px; padding: 0 28px;"&gt;&lt;/div&gt;

